import { useRef, useState } from "react";
import TextField from '../../atoms/textfield/textfield';

const AddFixture = ({currentFixtures, setFixtureIntoArray} : any) => {

    const [result, setResult] = useState();
    const [homeTeam, setHomeTeam] = useState();
    const [awayTeam, setAwayTeam] = useState();
    const [homeScore, setHomeScore] = useState();
    const [awayScore, setAwayScore] = useState();    

    const submit = (e : any) =>
    {
        e.preventDefault();        
        setFixtureIntoArray([...currentFixtures,
            {
                id: currentFixtures.length + 1,
                date: Date(),
                result: result,
                homeTeam: homeTeam,
                awayTeam: awayTeam,
                homeScore: homeScore,
                awayScore: awayScore,
                fixture: "League"
            }
        ]);

        setHomeTeam();
        setAwayTeam();
        setHomeScore();
        setAwayScore();
    } 

    return (
        <>
        <div className="row">
            <div className="form-group col-2">
                <label className="col-form-label">
                    Home Team<input className="form-control" title="hometeam" type="text" name="hometeam" value={fixture.homeTeam} onChange={(e) => setFixture({...fixture, homeTeam : e.target.value})}></input>        
                </label>
            </div>
            <div className="form-group col-2">
                <label className="col-form-label">        
                    Home Score<input className="form-control" title="homeScore" type="text" name="homeScore" value={fixture.homeScore} onChange={(e) => setFixture({...fixture, homeScore : e.target.value})}></input>        
                </label>
            </div>
            <div className="form-group col-2">     
                <label className="col-form-label">
                    Away Team<input className="form-control" title="awayTeam" type="text" name="awayTeam" value={fixture.awayTeam} onChange={(e) => setFixture({...fixture, awayTeam : e.target.value})}></input>        
                </label>
            </div>
            <div className="form-group col-2">               
                <TextField label="Away Score" title="awayScore" value={awayScore} callback={setAwayScore}></TextField>                                       
            </div>
            <div className="form-group col-2">
                <TextField label="Result (W/D/L)" title="result" value={result} callback={setResult}></TextField>               
            </div>    

        </div>
        <div className="col-2">
            <button className="btn btn-primary" type="submit" onClick={submit}>Add</button>
        </div>
        </>
    );
}

export default AddFixture;
